testcases.expected_optimized_ir:
declare i32 @llvm.usub.sat.i32(i32, i32)

define i1 @usub_sat_branch_dom_ult_i32(i32 %x, i32 %y, i32 %limit) {
entry:
  %pre = icmp ult i32 %x, %limit
  br i1 %pre, label %then, label %else

then:
  ret i1 true

else:
  ret i1 false
}

declare i8 @llvm.uadd.sat.i8(i8, i8)

define i1 @uadd_sat_branch_dom_ult_from_rhs_i8(i8 %x, i8 %y, i8 %lo) {
entry:
  %pre = icmp ult i8 %lo, %y
  br i1 %pre, label %then, label %else

then:
  ret i1 true

else:
  ret i1 false
}

